t.script:

let markedRowEmployeeId = null;
const markedCells = new Set();
const planningChanges = {};
// =============================
// CHANGE TRACKING (EXISTING)
// =============================
function onPlanningChange(el) {
    const dayId = el.dataset.dayId;
    const employeeId = el.dataset.employeeId;
    const scheduleId = el.value;

    el.classList.add('planning-changed');

    clearMarkedCells();

    planningChanges[dayId] = {
        day_id: parseInt(dayId),
        employee_id: parseInt(employeeId),
        working_schedule_id: parseInt(scheduleId)
    };
    showById("changes_button");
}

function confirmSavePlanning() {
    if (!confirm("Are you sure you want to save the planned working schedules?")) {
        return;
    }

    const changesArray = Object.values(planningChanges);

    if (!changesArray.length) {
        alert("No changes to save.");
        return;
    }

    submitData("schedule_changes", JSON.stringify(changesArray, null, 2));
}

function clearChangedCells() {
    document.querySelectorAll('.planning-changed').forEach(el => {
        el.classList.remove('planning-changed');
    });
    planningChanges = {};
    hideById("changes_button");
}

// =============================
// MARKING LOGIC (NEW)
// =============================

function onPlanningMark(el) {

    // ❌ Disable marking if there are unsaved changes
    if (Object.keys(planningChanges).length !== 0) {
        alert("Please save or discard changes before marking.");
        return;
    }

    const dayId = el.dataset.dayId;
    const employeeId = el.dataset.employeeId;

    // Reset if switching rows
    if (markedRowEmployeeId !== null) {
        if (markedRowEmployeeId !== employeeId) {
            clearMarkedCells();
        }
    }

    markedRowEmployeeId = employeeId;

    // Get all mark buttons for this employee row (DOM order = date order)
    const row = el.closest('tr');
    const buttons = Array.from(row.querySelectorAll('button[data-day-id]'));

    const clickedIndex = buttons.indexOf(el);

    // If already marked → unmark only if it's at the edge
    if (markedCells.has(dayId)) {
        markedCells.delete(dayId);
        el.classList.remove('planning-marked');

        if (markedCells.size === 0) {
            hideById("scheme_button");
        }

        return;
    }

    // Determine range to mark
    let indicesToMark = [clickedIndex];

    if (markedCells.size > 0) {
        const markedIndices = buttons
            .map((btn, idx) => markedCells.has(btn.dataset.dayId) ? idx : null)
            .filter(idx => idx !== null);

        const minIndex = Math.min.apply(null, markedIndices);
        const maxIndex = Math.max.apply(null, markedIndices);

        const start = Math.min(minIndex, clickedIndex);
        const end = Math.max(maxIndex, clickedIndex);

        indicesToMark = [];
        for (let i = start; i <= end; i++) {
            indicesToMark.push(i);
        }
    }

    // Enforce max 7
    if (indicesToMark.length > 7) {
        alert("You can mark up to 7 consecutive days per employee.");
        return;
    }

    // Apply marks
    indicesToMark.forEach(function (idx) {
        const btn = buttons[idx];
        const id = btn.dataset.dayId;

        if (!markedCells.has(id)) {
            markedCells.add(id);
            btn.classList.add('planning-marked');
        }
    });

    showById("scheme_button");
}

function clearMarkedCells() {
    document.querySelectorAll('.planning-marked').forEach(el => {
        el.classList.remove('planning-marked');
    });
    markedCells.clear();
    markedRowEmployeeId = null;
    hideById("scheme_button");
}

function confirmPlannedSchedule() {

    if (markedCells.size < 2) {
        alert("You have to select at least 2 cells");
        return;
    }

    if (!confirm("Are you sure you want to create days scheme for the selected days?")) {
        return;
    }

    if (!markedCells.size) {
        alert("No marked days.");
        return;
    }

    const result = {
        employee_id: parseInt(markedRowEmployeeId),
        day_ids: Array.from(markedCells).map(id => parseInt(id))
    };

    submitData("create_scheme", JSON.stringify(result, null, 2));
}

function hideById(id) {
    const el = document.getElementById(id);
    if (el) {
        el.style.display = 'none';
    }
}

function showById(id) {
    const el = document.getElementById(id);
    if (el) {
        el.style.display = '';
    }
}

function reloadPage(){
    window.location.reload();
}


function submitData(type, data) {

    const baseURL = '/sshr/planned_days_sub_employee_submit';
    const params = {
        type: type,
        data: data
    };

    try {
        const url = new URL(baseURL, window.location.origin);

        Object.keys(params).forEach(key => url.searchParams.append(key, params[key]));

        fetch(url)
            .then(response => response.text())
            .then(data => {
                console.log('Data saved successfully');
                reloadPage();
            })
            .catch(error => {
                reloadPage();
            });
    } catch (error) {
        console.error('Error constructing URL:', error);
        alert('Failed to construct URL');
    }

}
